import React from "react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { Loader2 } from "lucide-react";
import logo from "../assets/logo.png";
import { signInWithGoogle } from "../firebase";

export default function Home() {
  const navigate = useNavigate();
  const [loading, setLoading] = React.useState(false);

  const handleGoogleLogin = async () => {
    setLoading(true);
    try {
      await signInWithGoogle();
      navigate("/dashboard"); // or wherever your authenticated user lands
    } catch (err) {
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 1 }}
      className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-b from-black via-gray-900 to-black text-white text-center px-6"
    >
      {/* Logo Section */}
      <motion.img
        src={logo}
        alt="Godemar’s Empire"
        initial={{ scale: 0.8, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        transition={{ duration: 1 }}
        className="w-28 h-28 mb-6 drop-shadow-[0_0_20px_rgba(255,215,0,0.5)]"
      />

      {/* Heading */}
      <div className="max-w-3xl">
        <motion.h1
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3 }}
          className="text-2xl sm:text-4xl font-bold text-yellow-500 drop-shadow-lg mb-6"
        >
          Welcome to The Grand Coordinating Enterprise
        </motion.h1>

        <motion.p
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.5 }}
          className="text-gray-300 text-lg sm:text-xl mb-10 leading-relaxed"
        >
          Explore the world of innovation, creativity, and purpose. Join our empire of designers,
          thinkers, and creators shaping the future with brilliance.
        </motion.p>

        {/* Buttons */}
        <div className="flex flex-col sm:flex-row justify-center gap-6 mb-6">
          <button
            onClick={() => navigate("/login")}
            className="w-full sm:w-auto bg-yellow-500 hover:bg-yellow-400 text-black font-semibold py-3 px-8 rounded-xl shadow-lg transition duration-300 transform hover:scale-105"
          >
            Login
          </button>
          <button
            onClick={() => navigate("/signup")}
            className="w-full sm:w-auto bg-transparent border-2 border-yellow-500 text-yellow-400 hover:bg-yellow-500 hover:text-black font-semibold py-3 px-8 rounded-xl shadow-lg transition duration-300 transform hover:scale-105"
          >
            Sign Up
          </button>
        </div>

        {/* Google Login */}
        <motion.button
          onClick={handleGoogleLogin}
          disabled={loading}
          whileHover={{ scale: 1.05 }}
          className="flex items-center justify-center w-full sm:w-auto mx-auto bg-gray-900 border border-yellow-500 text-yellow-400 hover:bg-yellow-500 hover:text-black font-medium py-3 px-8 rounded-xl shadow-md transition duration-300"
        >
          {loading ? (
            <>
              <Loader2 className="animate-spin mr-2" size={20} />
              Connecting...
            </>
          ) : (
            "Continue with Google"
          )}
        </motion.button>

        {/* Footer */}
        <div className="mt-12">
          <p className="text-sm text-gray-500">
            © {new Date().getFullYear()} Godemar’s Empire — Built with vision and purpose.
          </p>
        </div>
      </div>
    </motion.div>
  );
}
